package com.evolua.user.interfaces.rest; import com.evolua.user.application.ProfileService; import com.evolua.user.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/profiles") public class ProfileController { private final ProfileService service; private final ProfileMapper mapper; private final CurrentUserProvider currentUserProvider; public ProfileController(ProfileService service, ProfileMapper mapper, CurrentUserProvider currentUserProvider) { this.service = service; this.mapper = mapper; this.currentUserProvider = currentUserProvider; } @PostMapping @Operation(summary = "Create Profile") public ResponseEntity<ApiResponse<ProfileResponse>> create(@Valid @RequestBody ProfileRequest request) { var created = service.create(currentUserProvider.getCurrentUser().userId(), request.displayName(), request.bio(), request.journeyLevel(), request.premium()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", mapper.toResponse(created))); } @GetMapping @Operation(summary = "List profiles") public ResponseEntity<ApiResponse<List<ProfileResponse>>> list() { return ResponseEntity.ok(ApiResponse.success(200, "Listed", service.list(currentUserProvider.getCurrentUser().userId()).stream().map(mapper::toResponse).toList())); } }
